def test_unauthenticated_user_cannot_create_announcement(api_client):
    payload = {
        "title": "Unauthorized Announcement",
        "body": "Should not be created.",
        "audience": "all"
    }
    resp = api_client.post("/org-announcements", json=payload)
    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}"

def test_create_announcement_missing_mandatory_field_returns_400(manager_auth_headers, api_client):
    payload = {
        "body": "Missing title field.",
        "audience": "all"
    }
    resp = api_client.post("/org-announcements", json=payload, headers=manager_auth_headers)
    assert resp.status_code == 400, f"Expected 400, got {resp.status_code}"
    error_data = resp.json()
    error_text = str(error_data).lower()
    assert "title" in error_text, "Validation error must reference missing 'title' field"

def test_forbidden_role_cannot_create_announcement(employee_auth_headers, api_client):
    payload = {
        "title": "Forbidden Role Announcement",
        "body": "Employee should not be allowed to create this.",
        "audience": "all"
    }
    resp = api_client.post("/org-announcements", json=payload, headers=employee_auth_headers)
    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}"
